class PriorityQueue<T> {
  private heap: T[];

  constructor() {
    this.heap = [];
  }

  enqueue(item: T, priority: number): void {
    this.heap.push({ item, priority });
    this._heapifyUp(this.heap.length - 1);
  }

  dequeue(): T | undefined {
    if (this.isEmpty()) return undefined;
    const item = this.heap[0].item;
    this.heap[0] = this.heap[this.heap.length - 1];
    this.heap.pop();
    this._heapifyDown(0);
    return item;
  }

  peek(): T | undefined {
    if (this.isEmpty()) return undefined;
    return this.heap[0].item;
  }

  isEmpty(): boolean {
    return this.heap.length === 0;
  }

  _heapifyUp(index: number): void {
    while (index > 0) {
      const parentIndex = Math.floor((index - 1) / 2);
      if (this.heap[parentIndex].priority >= this.heap[index].priority) break;
      [this.heap[parentIndex], this.heap[index]] = [this.heap[index], this.heap[parentIndex]];
      index = parentIndex;
    }
  }

  _heapifyDown(index: number): void {
    while (true) {
      const leftChildIndex = 2 * index + 1;
      const rightChildIndex = 2 * index + 2;
      let smallest = index;

      if (
        leftChildIndex < this.heap.length &&
        this.heap[leftChildIndex].priority < this.heap[smallest].priority
      ) {
        smallest = leftChildIndex;
      }

      if (
        rightChildIndex < this.heap.length &&
        this.heap[rightChildIndex].priority < this.heap[smallest].priority
      ) {
        smallest = rightChildIndex;
      }

      if (smallest === index) break;

      [this.heap[index], this.heap[smallest]] = [
        this.heap[smallest],
        this.heap[index],
      ];
      index = smallest;
    }
  }
}

// Test the PriorityQueue class
const priorityQueue = new PriorityQueue<string>();

priorityQueue.enqueue("item1", 10);
priorityQueue.enqueue("item2", 5);
priorityQueue.enqueue("item3", 15);

console.log(priorityQueue.dequeue()); // item1

console.log(priorityQueue.peek()); // item2

console.log(priorityQueue.isEmpty()); // false
